// Explicit return
function findMax(arr) {
  if (arr.length === 0) return -Infinity;
  let max = arr[0];
  for (const val of arr) {
    if (val > max) max = val;
  }
  return max;
}

// Implicit return with arrow
const double = (x) => x * 2;

